            email_cliente = cliente.email
            cliente.delete()
            messages.success(request, f'Cliente "{email_cliente}" eliminado exitosamente.')
        except User.DoesNotExist:
            return redirect('accounts:login')

        return redirect('admin_panel:clients_list')

