                    <th style="padding: 12px; text-align: left; border-bottom: 2px solid #ddd;">Acciones</th>
                </tr>
            </thead>
            <tbody>
                {% for info in clientes_info %}
                    <tr style="border-bottom: 1px solid #ddd;">
                        <td style="padding: 12px;">{{ info.cliente.email }}</td>
                        <td style="padding: 12px;">{{ info.cliente.nombre }}</td>
                        <td style="padding: 12px;">{{ info.total_reservas }}</td>
                        <td style="padding: 12px;">
                            {% if info.reservas_pendientes > 0 %}
                                <span style="color: #ff6b6b; font-weight: bold;">{{ info.reservas_pendientes }}</span>
                            {% else %}
                                <span style="color: green;">0</span>
                            {% endif %}
                        </td>
                        <td style="padding: 12px;">
                            {% if info.puede_eliminar %}
                                <form method="post" action="{% url 'admin_panel:clients_delete' info.cliente.id %}" style="display: inline;" onsubmit="return confirm('¿Estás seguro de que deseas eliminar este cliente?');">
                                    {% csrf_token %}
                                    <button type="submit" class="btn btn-danger" style="padding: 5px 10px; font-size: 12px;">Eliminar</button>
                                </form>
                            {% else %}
                                <button class="btn btn-danger" disabled style="padding: 5px 10px; font-size: 12px; opacity: 0.5; cursor: not-allowed;" title="No se puede eliminar: tiene reservas pendientes">Eliminar</button>
                            {% endif %}
                        </td>
                    </tr>
                {% endfor %}
            </tbody>
        </table>
    {% else %}
        <p>No hay clientes registrados.</p>
    {% endif %}
</div>
{% endblock %}

{% extends 'base.html' %}

{% block title %}Gestión de Reservas - Hundidos{% endblock %}

{% block content %}
<div style="max-width: 1000px; margin: 40px auto;">
    <h2>Gestión de Reservas</h2>

    <div style="margin-bottom: 20px;">
        <form method="get" style="display: flex; gap: 10px;">
            <select name="estado" style="padding: 10px; border: 1px solid #ddd; border-radius: 4px;">
                <option value="">Todos los estados</option>
                <option value="PENDIENTE_DE_PAGO" {% if estado_filtro == 'PENDIENTE_DE_PAGO' %}selected{% endif %}>Pendiente de Pago</option>
                <option value="PAGADO" {% if estado_filtro == 'PAGADO' %}selected{% endif %}>Pagado</option>
                <option value="EN_USO" {% if estado_filtro == 'EN_USO' %}selected{% endif %}>En Uso</option>
                <option value="DEVUELTO" {% if estado_filtro == 'DEVUELTO' %}selected{% endif %}>Devuelto</option>
                <option value="CANCELADA" {% if estado_filtro == 'CANCELADA' %}selected{% endif %}>Cancelada</option>
            </select>
            <button type="submit" class="btn" style="padding: 10px 20px;">Filtrar</button>
            <a href="{% url 'admin_panel:reservations_list' %}" class="btn btn-secondary" style="padding: 10px 20px;">Limpiar</a>
        </form>
    </div>

    {% if reservas %}
        <table style="width: 100%; border-collapse: collapse; background-color: white;">
            <thead>
                <tr style="background-color: #f5f5f5;">
                    <th style="padding: 12px; text-align: left; border-bottom: 2px solid #ddd;">Código</th>
                    <th style="padding: 12px; text-align: left; border-bottom: 2px solid #ddd;">Cliente</th>
                    <th style="padding: 12px; text-align: left; border-bottom: 2px solid #ddd;">Estado</th>
                    <th style="padding: 12px; text-align: left; border-bottom: 2px solid #ddd;">Fecha Inicio</th>
                    <th style="padding: 12px; text-align: left; border-bottom: 2px solid #ddd;">Total</th>
                    <th style="padding: 12px; text-align: left; border-bottom: 2px solid #ddd;">Acciones</th>
                </tr>
            </thead>
            <tbody>
                {% for reserva in reservas %}
                    <tr style="border-bottom: 1px solid #ddd;">
                        <td style="padding: 12px;">{{ reserva.codigo_seguimiento }}</td>
                        <td style="padding: 12px;">{{ reserva.nombre_cliente }}</td>
                        <td style="padding: 12px;">
                            <span style="padding: 4px 8px; border-radius: 4px; font-size: 12px; font-weight: bold;
                            {% if reserva.estado == 'PENDIENTE_DE_PAGO' %}
                                background-color: #fff3cd; color: #856404;
                            {% elif reserva.estado == 'PAGADO' %}
                                background-color: #d4edda; color: #155724;
                            {% elif reserva.estado == 'EN_USO' %}
                                background-color: #d1ecf1; color: #0c5460;
                            {% elif reserva.estado == 'DEVUELTO' %}
                                background-color: #e2e3e5; color: #383d41;
                            {% elif reserva.estado == 'CANCELADA' %}
                                background-color: #f8d7da; color: #721c24;
                            {% endif %}
                            ">{{ reserva.get_estado_display }}</span>
                        </td>
                        <td style="padding: 12px;">{{ reserva.fecha_inicio|date:"d/m/Y" }}</td>
                        <td style="padding: 12px;">€{{ reserva.importe_total }}</td>
                        <td style="padding: 12px;">
                            <a href="{% url 'admin_panel:reservations_detail' reserva.id %}" class="btn" style="padding: 5px 10px; font-size: 12px;">Ver Detalles</a>
                        </td>
                    </tr>
                {% endfor %}
            </tbody>
        </table>
    {% else %}
        <p>No hay reservas registradas.</p>
    {% endif %}
</div>
{% endblock %}
